import React, { useEffect, useState } from 'react';
import { useUserStore } from './userStore';
import { useNavigate } from 'react-router-dom';
import { getCustomer } from './woocommerce';

const MyAccount = () => {
  const navigate = useNavigate();
  const { user, isAuthenticated, logout } = useUserStore();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    } else {
      fetchCustomerData();
    }
  }, [isAuthenticated, navigate]);

  const fetchCustomerData = async () => {
    try {
      setLoading(true);
      // In a real implementation, you would fetch orders here
      // For now, this is a placeholder
      setOrders([]);
    } catch (error) {
      console.error('Error fetching customer data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  if (!isAuthenticated) {
    return null;
  }

  return (
    <div className="my-account">
      <header className="header">
        <div className="header-content">
          <h1>Ritchie Street Electronics</h1>
          <nav className="nav">
            <Link to="/">Home</Link>
            <Link to="/cart">Cart ({getCartCount()})</Link>
            <Link to="/my-account">My Account</Link>
          </nav>
        </div>
      </header>

      <div className="account-container">
        <div className="account-sidebar">
          <div className="user-info">
            <h3>{user?.first_name || 'User'}</h3>
            <p>{user?.email}</p>
          </div>

          <nav className="account-nav">
            <a href="#dashboard" className="active">Dashboard</a>
            <a href="#orders">Orders</a>
            <a href="#addresses">Addresses</a>
            <a href="#account-details">Account Details</a>
            <button onClick={handleLogout} className="logout-btn">Logout</button>
          </nav>
        </div>

        <div className="account-content">
          <section id="dashboard" className="account-section">
            <h2>My Account</h2>
            <p>Hello {user?.first_name || 'User'}!</p>
            <p>From your account dashboard you can view your recent orders, manage your shipping and billing addresses, and edit your password and account details.</p>
          </section>

          <section id="orders" className="account-section">
            <h2>My Orders</h2>
            {loading ? (
              <p>Loading orders...</p>
            ) : orders.length > 0 ? (
              <table className="orders-table">
                <thead>
                  <tr>
                    <th>Order</th>
                    <th>Date</th>
                    <th>Status</th>
                    <th>Total</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {orders.map(order => (
                    <tr key={order.id}>
                      <td>#{order.id}</td>
                      <td>{new Date(order.date_created).toLocaleDateString()}</td>
                      <td>{order.status}</td>
                      <td>₹{order.total}</td>
                      <td>
                        <button>View</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p>No orders yet.</p>
            )}
          </section>

          <section id="addresses" className="account-section">
            <h2>Addresses</h2>
            <div className="addresses-grid">
              <div className="address-box">
                <h3>Billing Address</h3>
                <p>{user?.first_name} {user?.last_name}</p>
                <p>{user?.billing_address_1}</p>
                <p>{user?.billing_city}, {user?.billing_state}</p>
                <p>{user?.billing_postcode}</p>
                <p>{user?.email}</p>
                <p>{user?.billing_phone}</p>
                <button>Edit</button>
              </div>

              <div className="address-box">
                <h3>Shipping Address</h3>
                <p>You have not set up a shipping address yet.</p>
                <button>Add</button>
              </div>
            </div>
          </section>

          <section id="account-details" className="account-section">
            <h2>Account Details</h2>
            <form className="account-form">
              <div className="form-row">
                <div className="form-group">
                  <label>First Name *</label>
                  <input type="text" defaultValue={user?.first_name} />
                </div>
                <div className="form-group">
                  <label>Last Name *</label>
                  <input type="text" defaultValue={user?.last_name} />
                </div>
              </div>

              <div className="form-group">
                <label>Email Address *</label>
                <input type="email" defaultValue={user?.email} />
              </div>

              <div className="form-group">
                <label>Current Password (leave blank to leave unchanged)</label>
